import os
import sys
import json
import time
from urllib.parse import urljoin
import requests

DEFAULT_TIMEOUT = 15


class KongAdminError(Exception):
    pass


def env(name, default=None):
    v = os.getenv(name)
    return v if v is not None else default


def to_bool(v, default=False):
    if v is None:
        return default
    return str(v).strip().lower() in ("1", "true", "yes", "y", "on")


def join_admin(base, path):
    base = base.rstrip("/") + "/"
    path = path.lstrip("/")
    return urljoin(base, path)


def request_json(method, url, *, headers=None, params=None, data=None, json_body=None, timeout=DEFAULT_TIMEOUT, retries=3, retry_backoff=0.7):
    last_exc = None
    for i in range(max(1, retries)):
        try:
            resp = requests.request(
                method,
                url,
                headers=headers,
                params=params,
                data=data,
                json=json_body,
                timeout=timeout,
            )
            if 200 <= resp.status_code < 300:
                if resp.text.strip() == "":
                    return None
                ct = resp.headers.get("Content-Type", "")
                if "application/json" in ct:
                    return resp.json()
                try:
                    return resp.json()
                except Exception:
                    return resp.text
            else:
                body = resp.text
                raise KongAdminError(f"{method} {url} -> {resp.status_code} {body}")
        except (requests.RequestException, KongAdminError) as e:
            last_exc = e
            if i < retries - 1:
                time.sleep(retry_backoff * (2 ** i))
                continue
            raise
    raise last_exc


def build_headers(admin_token=None, extra_headers=None):
    headers = {"Accept": "application/json"}
    if admin_token:
        headers["Kong-Admin-Token"] = admin_token
    if extra_headers:
        headers.update(extra_headers)
    return headers


def ensure_service(admin, headers, svc):
    name = svc.get("name")
    if not name:
        raise ValueError("service missing required field: name")

    payload = {k: v for k, v in svc.items() if v is not None and k != "routes"}
    url = join_admin(admin, f"services/{name}")
    return request_json("PUT", url, headers=headers, json_body=payload)


def ensure_route(admin, headers, service_name, route):
    name = route.get("name")
    if not name:
        raise ValueError("route missing required field: name")

    payload = {k: v for k, v in route.items() if v is not None}
    payload["service"] = {"name": service_name}

    url = join_admin(admin, f"routes/{name}")
    return request_json("PUT", url, headers=headers, json_body=payload)


def ensure_upstream(admin, headers, upstream):
    name = upstream.get("name")
    if not name:
        raise ValueError("upstream missing required field: name")

    payload = {k: v for k, v in upstream.items() if v is not None and k != "targets"}
    url = join_admin(admin, f"upstreams/{name}")
    return request_json("PUT", url, headers=headers, json_body=payload)


def add_target(admin, headers, upstream_name, target):
    target_str = target.get("target")
    if not target_str:
        raise ValueError("target missing required field: target (e.g. '10.0.0.12:8080')")

    payload = {k: v for k, v in target.items() if v is not None}
    url = join_admin(admin, f"upstreams/{upstream_name}/targets")
    return request_json("POST", url, headers=headers, json_body=payload)


def health_check(admin, headers):
    url = join_admin(admin, "/status")
    return request_json("GET", url, headers=headers)


def load_config(path):
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def apply_config(admin, headers, config, *, stop_on_error=True):
    results = {"services": [], "routes": [], "upstreams": [], "targets": [], "errors": []}

    services = config.get("services", [])
    upstreams = config.get("upstreams", [])

    for up in upstreams:
        try:
            res = ensure_upstream(admin, headers, up)
            results["upstreams"].append(res)
            for t in up.get("targets", []) or []:
                try:
                    tres = add_target(admin, headers, up["name"], t)
                    results["targets"].append(tres)
                except Exception as e:
                    err = {"type": "target", "upstream": up.get("name"), "target": t, "error": str(e)}
                    results["errors"].append(err)
                    if stop_on_error:
                        raise
        except Exception as e:
            err = {"type": "upstream", "upstream": up.get("name"), "error": str(e)}
            results["errors"].append(err)
            if stop_on_error:
                raise

    for svc in services:
        try:
            sres = ensure_service(admin, headers, svc)
            results["services"].append(sres)
            for r in svc.get("routes", []) or []:
                try:
                    rres = ensure_route(admin, headers, svc["name"], r)
                    results["routes"].append(rres)
                except Exception as e:
                    err = {"type": "route", "service": svc.get("name"), "route": r, "error": str(e)}
                    results["errors"].append(err)
                    if stop_on_error:
                        raise
        except Exception as e:
            err = {"type": "service", "service": svc.get("name"), "error": str(e)}
            results["errors"].append(err)
            if stop_on_error:
                raise

    return results


