def parse_args(argv):
    import argparse

    p = argparse.ArgumentParser(description="Configure Kong Gateway (services/routes/upstreams/targets) via Admin API")
    p.add_argument("--admin", default=env("KONG_ADMIN_URL", "http://localhost:8001"), help="Kong Admin API base URL")
    p.add_argument("--token", default=env("KONG_ADMIN_TOKEN"), help="Kong Admin API token (Kong-Admin-Token)")
    p.add_argument("--config", default=env("KONG_CONFIG_PATH"), help="Path to JSON config file")
    p.add_argument("--stop-on-error", action="store_true", default=to_bool(env("KONG_STOP_ON_ERROR"), False))
    p.add_argument("--timeout", type=int, default=int(env("KONG_TIMEOUT", DEFAULT_TIMEOUT)))
    p.add_argument("--retries", type=int, default=int(env("KONG_RETRIES", 3)))
    p.add_argument("--print-example", action="store_true", help="Print example config JSON and exit")
    p.add_argument("--insecure", action="store_true", default=to_bool(env("KONG_INSECURE"), False), help="Disable TLS verification")
    return p.parse_args(argv)


def main(argv):
    args = parse_args(argv)

    if args.print_example:
        print(json.dumps(example_config(), indent=2, sort_keys=True))
        return 0

    if not args.config:
        print("Missing --config (or KONG_CONFIG_PATH). Use --print-example for a template.", file=sys.stderr)
        return 2

    cfg = load_config(args.config)

    admin = args.admin
    token = args.token
    headers = build_headers(token)

    requests.packages.urllib3.disable_warnings()  # noqa
    if args.insecure:
        requests.Session().verify = False

    global DEFAULT_TIMEOUT
    DEFAULT_TIMEOUT = args.timeout

    try:
        health = health_check(admin, headers)
    except Exception as e:
        print(f"Failed to reach Kong Admin API at {admin}: {e}", file=sys.stderr)
        return 1

    try:
        results = apply_config(admin, headers, cfg, stop_on_error=args.stop_on_error)
    except Exception as e:
        print(f"Apply failed: {e}", file=sys.stderr)
        return 1

    out = {
        "admin": admin,
        "status": health,
        "applied": {
            "services": len(results["services"]),
            "routes": len(results["routes"]),
            "upstreams": len(results["upstreams"]),
            "targets": len(results["targets"]),
            "errors": len(results["errors"]),
        },
        "errors": results["errors"],
    }
    print(json.dumps(out, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))